content:
run this strategy over that instrument, timeframe and date range go get the data we need
===STRATEGY_JSON_START===
{
  "entry_long": {
    "all": [
      {"field": "adx_14", "op": "gt", "value": 25},
      {"field": "ema_slope_20", "op": "gt", "value": 0},
      {"field": "ema_slope_50", "op": "gt", "value": 0},
      {"field": "ema_slope_20", "op": "gt", "field2": "ema_slope_50"},
      {"ref": "price_below_ema20_threshold"},
      {"ref": "not_friday"}
    ]
  },
  "entry_short": {
    "all": [
      {"field": "adx_14", "op": "gt", "value": 25},
      {"field": "ema_slope_20", "op": "lt", "value": 0},
      {"field": "ema_slope_50", "op": "lt", "value": 0},
      {"field": "ema_slope_20", "op": "lt", "field2": "ema_slope_50"},
      {"ref": "price_above_ema20_threshold"},
      {"ref": "not_friday"}
    ]
  },
  "exit": {
    "any": [
      {"ref": "max_hold_period"},
      {"ref": "friday_close"}
    ]
  },
  "stop_atr_multiplier": 2.5,
  "take_profit_atr_multiplier": 4.0,
  "position_size_units": 1000,
  "named_conditions": {
    "price_below_ema20_threshold": {
      "field": "log_ret_1", 
      "op": "lt", 
      "value": -0.015
    },
    "price_above_ema20_threshold": {
      "field": "log_ret_1", 
      "op": "gt", 
      "value": 0.015
    },
    "max_hold_period": {
      "field": "minutes_in_trade", 
      "op": "gte", 
      "value": 7200
    },
    "friday_close": {
      "field": "day_of_week", 
      "op": "eq", 
      "value": 4
    },
    "not_friday": {
      "field": "day_of_week", 
      "op": "neq", 
      "value": 4
    }
  }
}
===STRATEGY_JSON_END===
